parameters.jsCode:
const rows = $input.all();

let totalRevenue = 0;
let totalQuantity = 0;

const productQty = {};
const productRevenue = {};
const cashierRevenue = {};
const cityRevenue = {};
const categoryRevenue = {};
const monthlyRevenue = {};

for (const item of rows) {

  const row = item.json;

  const revenue = Number(row.Revenue || 0);
  const qty = Number(row.Quantity || 0);

  totalRevenue += revenue;
  totalQuantity += qty;

  // Product Qty
  productQty[row.Product] =
    (productQty[row.Product] || 0) + qty;

  // Product Revenue
  productRevenue[row.Product] =
    (productRevenue[row.Product] || 0) + revenue;

  // Cashier Revenue
  cashierRevenue[row.Cashier] =
    (cashierRevenue[row.Cashier] || 0) + revenue;

  // City Revenue
  cityRevenue[row.City] =
    (cityRevenue[row.City] || 0) + revenue;

  // Category Revenue
  categoryRevenue[row.Category] =
    (categoryRevenue[row.Category] || 0) + revenue;

  // Monthly Revenue
  const month = String(row.Date).substring(0,7);

  monthlyRevenue[month] =
    (monthlyRevenue[month] || 0) + revenue;
}


// Top Product By Quantity
const topProduct =
  Object.entries(productQty)
    .sort((a,b)=>b[1]-a[1])[0];


// Highest Revenue Product
const topRevenueProduct =
  Object.entries(productRevenue)
    .sort((a,b)=>b[1]-a[1])[0];


// Best Cashier
const bestCashier =
  Object.entries(cashierRevenue)
    .sort((a,b)=>b[1]-a[1])[0];


// Best City
const topCity =
  Object.entries(cityRevenue)
    .sort((a,b)=>b[1]-a[1])[0];


// Best Category
const topCategory =
  Object.entries(categoryRevenue)
    .sort((a,b)=>b[1]-a[1])[0];


// Best Month
const bestMonth =
  Object.entries(monthlyRevenue)
    .sort((a,b)=>b[1]-a[1])[0];


// Top 5 Products
const top5Products =
  Object.entries(productQty)
    .sort((a,b)=>b[1]-a[1])
    .slice(0,5)
    .map(([product, qty]) => ({
      product,
      qty
    }));


return [
{
json:{

totalRevenue,
totalQuantity,

topProduct: topProduct[0],
topProductQty: topProduct[1],

topRevenueProduct: topRevenueProduct[0],
topRevenueProductRevenue: topRevenueProduct[1],

bestCashier: bestCashier[0],
bestCashierRevenue: bestCashier[1],

topCity: topCity[0],
topCityRevenue: topCity[1],

topCategory: topCategory[0],
topCategoryRevenue: topCategory[1],

bestMonth: bestMonth[0],
bestMonthRevenue: bestMonth[1],

top5Products,

categoryRevenue,

monthlyRevenue

}
}
];

const data = $json;

const recommendations = [];

// Revenue trend
if (
  data.bestMonthRevenue &&
  data.totalRevenue
) {
  recommendations.push(
    `Best performing month is ${data.bestMonth}.`
  );
}

// Top product
recommendations.push(
  `Maintain strong inventory levels for ${data.topProduct}.`
);

// Top city
recommendations.push(
  `${data.topCity} is currently the strongest market.`
);

// Best cashier
recommendations.push(
  `${data.bestCashier} is the top-performing cashier.`
);

// Category
recommendations.push(
  `Focus promotions on the ${data.topCategory} category.`
);

return [{
  json: {
    ...data,
    recommendations
  }
}];
